import React, { useState, useCallback } from 'react';
import { ImportItem, AnalysisResult } from './types';
import ImportForm from './components/ImportForm';
import ResultDisplay from './components/ResultDisplay';
import { analyzeImportData } from './services/geminiService';

const App: React.FC = () => {
  const [items, setItems] = useState<ImportItem[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const addItem = useCallback((item: ImportItem) => {
    setItems(prev => [...prev, item]);
    setResult(null); // Clear previous results when list changes
  }, []);

  const removeItem = (id: string) => {
    setItems(prev => prev.filter(i => i.id !== id));
    setResult(null);
  };

  const handleProcess = async () => {
    if (items.length === 0) return;

    setIsAnalyzing(true);
    setError(null);
    try {
      const analysis = await analyzeImportData(items);
      setResult(analysis);
    } catch (err: any) {
      setError(err.message || 'Ocorreu um erro na análise.');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
