            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tighter italic">IMPORTATECH <span className="text-blue-500">BRASIL</span></h1>
              <p className="text-xs text-slate-400 font-medium">Classificação Inteligente & Blindagem Aduaneira</p>
            </div>
          </div>
          <div className="hidden md:flex gap-4 text-xs font-bold uppercase tracking-widest text-slate-500">
            <span>Receita Federal Compliance</span>
            <span>Têxtil Expert</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 gap-8">

          {/* Step 1: Add Items */}
          <section>
            <ImportForm onAddItem={addItem} />
          </section>

          {/* Step 2: List Current Items */}
          {items.length > 0 && (
            <section className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-slate-800">Itens no Lote ({items.length})</h3>
                <button 
                  onClick={() => setItems([])}
                  className="text-xs text-red-500 hover:text-red-700 font-bold uppercase"
                >
                  Limpar Tudo
                </button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {items.map(item => (
                  <div key={item.id} className="border border-slate-100 bg-slate-50 p-4 rounded-lg relative group transition-all hover:border-blue-200">
                    <button 
                      onClick={() => removeItem(item.id)}
                      className="absolute top-2 right-2 text-slate-300 hover:text-red-500 transition-colors"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                    </button>
                    <div className="font-bold text-slate-800 text-sm">{item.name}</div>
