          <p className="text-sm font-bold text-slate-700 mb-2 uppercase tracking-widest">🧱 Blindagem Legal</p>
          <p className="text-xs leading-relaxed italic">
            Esta plataforma não realiza declarações oficiais nem garante isenção tributária. As informações geradas são estimativas técnicas baseadas nas normas da Receita Federal e devem ser revisadas pelo importador ou seu despachante aduaneiro. A tributação final e o desembaraço são definidos exclusivamente pelas autoridades alfandegárias competentes.
          </p>
        </div>
        <p className="text-center text-[10px] text-slate-400 mt-4 uppercase font-medium">
          ImportaTech Brasil © 2024 - Tecnologia para Importação Consciente
        </p>
      </footer>
    </div>
  );
};

export default App;

